INSERT INTO `conteudos_publicos` (`id`, `hero_titulo`, `hero_subtitulo`, `sobre_titulo`, `sobre_texto_1`, `sobre_texto_2`, `sobre_texto_3`, `servicos_titulo`, `servicos_texto`, `clientes_titulo`, `clientes_texto`, `contactos_titulo`, `contactos_texto`, `morada`, `telefone`, `email`, `website`, `horario`, `rodape_texto`, `atualizado_por`, `atualizado_em`) VALUES
	(1, 'Soluções digitais para a gestão hospitalar', 'Desenvolvemos sistemas de informação especializados para instituições de saúde, com foco na rastreabilidade, segurança e eficiência operacional.', 'Sobre Nós', 'A MedInfo Solutions é uma empresa portuguesa especializada no desenvolvimento de software para a área da saúde. Fundada em 2015 e sediada no Porto, temos como missão modernizar a gestão tecnológica das instituições de saúde nacionais.', 'A nossa equipa é composta por engenheiros biomédicos, engenheiros informáticos e especialistas em sistemas de informação hospitalares, o que nos permite desenvolver soluções tecnicamente sólidas e clinicamente adequadas.', 'Trabalhamos com hospitais públicos e privados, clínicas e centros de saúde em todo o território nacional, com especial foco em sistemas de gestão de inventário e manutenção de equipamentos médicos.', 'Serviços', 'Desenvolvemos soluções adaptadas às necessidades específicas de cada instituição.', 'Os Nossos Clientes', 'Trabalhamos com algumas das principais instituições de saúde nacionais.', 'Contactos', 'Entre em contacto connosco para mais informações ou para agendar uma demonstração.', 'Rua Dr. António Bernardino de Almeida, 431\n4200-072 Porto', '+351 222 123 456', 'geral@medinfosolutions.pt', 'www.medinfosolutions.pt', '2ª a 6ª Feira: 9h — 18h\nSábado, Domingo e Feriados: Encerrado', 'MedInfo Solutions © 2025 — Todos os direitos reservados', NULL, '2026-06-23 19:48:15');
